const LOC_ORDER=['bloom','pond','forest','hills','mushroom','whisker','lookout','cottage'];
// 각 위치의 기본 해금 날짜 (startLoc으로 선택된 곳은 Day 1)
// cottage는 항상 0 (처음부터)
const LOC_UNLOCK_BASE={
  bloom:1, pond:1, forest:2, hills:2, mushroom:3, whisker:5, lookout:4, cottage:0
};
// 실제 해금 계산: G.startLoc 기준으로 오프셋
function getLocUnlockDay(key){
  if(key==='cottage') return 0; // 항상 개방
  if(!G.startLoc || key===G.startLoc) return 1; // 시작 장소
  // LOC_ORDER에서 순서
  const order=['bloom','pond','forest','hills','mushroom','whisker','lookout'];
  const startIdx=order.indexOf(G.startLoc);
  const keyIdx=order.indexOf(key);
  if(startIdx<0||keyIdx<0) return LOC_UNLOCK_BASE[key]||1;
  const offset=(keyIdx-startIdx+order.length)%order.length;
  return offset===0?1:Math.max(1,offset*1+1); // +1일씩
}
function isLocUnlocked(key){
  return G.day>=getLocUnlockDay(key);
}

