// 원정 도착 시 탐험 이벤트 표시
function showExpeditionExplore(missionId, onComplete){
  var events = EXPEDITION_EVENTS[missionId];
  if(!events || events.length===0){ onComplete(); return; }
  
  // 랜덤 이벤트 선택
  var ev = events[Math.floor(Math.random()*events.length)];
  
  var overlay = document.createElement('div');
  overlay.id = 'expedition-explore-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;z-index:300;background:rgba(5,10,5,.97);display:flex;flex-direction:column;overflow-y:auto;padding:20px;font-family:Nanum Myeongjo,serif';
  
  // 장소별 색상
  var colors = {deepforest:['#80d080','#2a6a2a'],frostpaw:['#a0d0ff','#3a6aaa'],desert:['#f0d080','#a08030'],library:['#d0b080','#806030']};
  var col = colors[missionId]||['#d0b080','#806030'];
  
  overlay.innerHTML = '<div style="max-width:480px;margin:0 auto;width:100%">'
    +'<div style="text-align:center;padding:16px 0 12px">'
    +'<div style="font-size:2rem;margin-bottom:6px">🗺️</div>'
    +'<div style="font-family:Cinzel,serif;font-size:1rem;color:'+col[0]+'">현지 탐험</div>'
    +'</div>'
    +'<div style="padding:14px;border-radius:10px;border:1.5px solid '+col[1]+';background:rgba(0,0,0,.3);margin-bottom:14px">'
    +'<div style="font-family:Cinzel,serif;font-size:.9rem;color:'+col[0]+';margin-bottom:8px">'+ev.title+'</div>'
    +'<div style="font-size:.82rem;color:rgba(255,255,255,.75);line-height:1.7">'+ev.desc+'</div>'
    +'</div>'
    +'<div style="font-size:.75rem;color:rgba(255,255,255,.5);margin-bottom:10px;text-align:center">어떻게 할까요?</div>'
    +'<div id="explore-choices"></div>'
    +'</div>';
  
  document.body.appendChild(overlay);
  
  var choicesEl = overlay.querySelector('#explore-choices');
  ev.choices.forEach(function(choice){
    var btn = document.createElement('button');
    btn.style.cssText = 'width:100%;padding:12px 14px;border-radius:10px;border:1.5px solid '+col[1]+';background:rgba(255,255,255,.05);color:rgba(255,255,255,.85);font-family:Nanum Myeongjo,serif;font-size:.85rem;cursor:pointer;text-align:left;margin-bottom:8px;display:block;transition:all .15s';
    btn.textContent = choice.label;
    btn.onmouseover = function(){ btn.style.background='rgba(255,255,255,.1)'; };
    btn.onmouseout  = function(){ btn.style.background='rgba(255,255,255,.05)'; };
    btn.onclick = function(){
      var result = choice.result();
      if(result.extra) result.extra();
      showExploreResult(result, col, missionId, onComplete);
      overlay.remove();
    };
    choicesEl.appendChild(btn);
  });
}

function showExploreResult(result, col, missionId, onComplete){
  var overlay2 = document.createElement('div');
  overlay2.id = 'expedition-explore-result';
  overlay2.style.cssText = 'position:fixed;inset:0;z-index:301;background:rgba(5,10,5,.97);display:flex;flex-direction:column;align-items:center;justify-content:center;padding:20px;font-family:Nanum Myeongjo,serif';
  
  overlay2.innerHTML = '<div style="max-width:420px;width:100%;text-align:center">'
    +'<div style="font-size:3rem;margin-bottom:10px">'+result.icon+'</div>'
    +'<div style="font-size:.9rem;color:rgba(255,255,255,.85);line-height:1.7;margin-bottom:20px;padding:14px;border-radius:10px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1)">'+result.text+'</div>'
    +(result.mob
      ? '<button id="explore-battle-btn" style="width:100%;padding:13px;border-radius:10px;border:1.5px solid #cc4444;background:rgba(200,50,50,.2);color:#ff8888;font-family:Nanum Myeongjo,serif;font-size:.9rem;cursor:pointer;margin-bottom:8px">⚔️ 전투 준비!</button>'
      : '')
    +'<button id="explore-continue-btn" style="width:100%;padding:13px;border-radius:10px;border:1.5px solid rgba(255,255,255,.2);background:rgba(255,255,255,.06);color:rgba(255,255,255,.7);font-family:Nanum Myeongjo,serif;font-size:.88rem;cursor:pointer">🏠 탐험 마치고 귀환</button>'
    +'</div>';
  
  document.body.appendChild(overlay2);
  updateUI();
  
  if(result.mob){
    overlay2.querySelector('#explore-battle-btn').onclick = function(){
      overlay2.remove();
      setTimeout(function(){ startBattle2(result.mob, result.zone||missionId); }, 300);
      // 전투 후 onComplete 연결은 handleBattle2Win에서 처리
      window._pendingExpeditionComplete = onComplete;
    };
  }
  overlay2.querySelector('#explore-continue-btn').onclick = function(){
    overlay2.remove();
    onComplete();
  };
}

