const CIRCUS_EVENTS = [
  {
    title:'🎪 떠돌이 서커스단 출현!',
    icon:'🎪',
    desc:'화려한 천막이 정원 근처에 나타났습니다! Purrelli & Sons Travelling Circus가 이틀간 머뭅니다.',
    rewards:[
      {label:'🎭 공연 관람 (재료 1개 선물)', action:()=>{
        const items=['herb','lotus','shroom','rare'];
        const item=items[Math.floor(Math.random()*items.length)];
        addHerb(item,2);
        spawnFloat('🎪 공연 감사 선물! +'+iN(item)+'×2');
      }},
      {label:'🛒 서커스 상단과 교역 (코인 5 → 희귀초 2)', action:()=>{
        if((G.coins.bronze||0)>=5){G.coins.bronze-=5;addHerb('rare',2);spawnFloat('🎪 교역 완료! 희귀초×2');}
        else showResult('🪙 코인이 부족합니다!',true);
      }},
      {label:'🤸 서커스 묘기 도전 (랜덤 보상)', action:()=>{
        const luck=Math.random();
        if(luck>0.6){addHerb('rare',3);addCoins('bronze',10);spawnFloat('🎉 묘기 성공! 대박 보상!');}
        else if(luck>0.3){addHerb('herb',3);addHerb('shroom',2);spawnFloat('👏 묘기 성공! 재료 획득!');}
        else{G.energy=Math.max(0,(G.energy||0)-1);spawnFloat('😅 묘기 실패... Activity -1');}
      }},
      {label:'그냥 지나치기', action:()=>spawnFloat('🎪 서커스단이 멀어집니다...')},
    ]
  },
];

function tryCircusEvent(){
  if(!G.circusDay) G.circusDay=0;
  // 5~7일마다 한 번, Day 8 이후
  if(G.day >= 8 && G.day - G.circusDay >= 5 + Math.floor(Math.random()*3)){
    if(Math.random() < 0.3){
      G.circusDay = G.day;
      triggerCircusEvent();
    }
  }
}

function triggerCircusEvent(){
  const ev = CIRCUS_EVENTS[Math.floor(Math.random()*CIRCUS_EVENTS.length)];
  const overlay = document.getElementById('walk-overlay');
  document.getElementById('walk-title').textContent = ev.title;
  document.getElementById('walk-desc').textContent = ev.desc;
  const rewardDiv = document.getElementById('walk-rewards');
  rewardDiv.innerHTML='';
  ev.rewards.forEach(r=>{
    const btn=document.createElement('button');
    btn.className='walk-reward';
    btn.textContent=r.label;
    btn.onclick=()=>{r.action();updateUI();updateMineUI();closeWalk();};
    rewardDiv.appendChild(btn);
  });
  overlay.classList.add('show');
  log('[서커스단] Purrelli & Sons 출현!');
  spawnFloat('🎪 떠돌이 서커스단이 나타났다!');
}

function tryWalkEvent(){
  if(Math.random() < 0.15 && G.day >= 5){
    triggerWalkEvent();
  }
  tryCircusEvent();
}

function triggerWalkEvent(){
  const ev = WALK_EVENTS[Math.floor(Math.random()*WALK_EVENTS.length)];
  G.walkActive = true;
  const overlay = document.getElementById('walk-overlay');
  document.getElementById('walk-title').textContent='🦕 '+ev.title;
  document.getElementById('walk-desc').textContent=ev.desc;
  const rewardDiv = document.getElementById('walk-rewards');
  rewardDiv.innerHTML='';
  ev.rewards.forEach(r=>{
    const btn=document.createElement('button');
    btn.className='walk-reward';
    btn.textContent=r.label;
    btn.onclick=()=>{r.action();updateUI();updateMineUI();closeWalk();};
    rewardDiv.appendChild(btn);
  });
  overlay.classList.add('show');
  log(`[워킹하우스] ${ev.title}`);
  spawnFloat('🦕 집이 걷기 시작했다!');
}

function closeWalk(){
  document.getElementById('walk-overlay').classList.remove('show');
  G.walkActive=false;
}

