// 조합 상태
var comboSelected = [];
var comboResult = null;

function initSecretCombo(){
  renderComboHerbs();
  renderComboInventory();
}

function renderComboHerbs(){
  var grid = document.getElementById('combo-herb-grid');
  if(!grid) return;
  grid.innerHTML = '';

  COMBO_HERBS.forEach(function(h){
    var have = (G.herbs&&G.herbs[h.id])||0;
    if(h.id==='lubelily'||h.id==='rustcap'||h.id==='voltcreep'){
      have = (G.herbCollected&&G.herbCollected[h.id])||0;
    }
    var selected = comboSelected.indexOf(h.id) >= 0;
    var btn = document.createElement('button');
    btn.style.cssText = 'display:flex;align-items:center;gap:6px;padding:7px 8px;'
      +'border-radius:8px;border:2px solid '+(selected?'var(--gold)':'var(--parch3)')+';'
      +'background:'+(selected?'rgba(184,137,26,.18)':'var(--parch)')+';'
      +'cursor:'+(have>0?'pointer':'default')+';opacity:'+(have>0?'1':'.35')+';'
      +'transition:all .15s;width:100%;text-align:left;';
    btn.innerHTML = '<span style="font-size:1.4rem;flex-shrink:0">'+h.icon+'</span>'
      +'<div style="flex:1;min-width:0">'
      +'<div style="font-size:.68rem;color:var(--ink);font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+h.name+'</div>'
      +'<div style="font-size:.58rem;color:var(--ink2)">보유 '+have+'개'+(selected?' ✓':'')+'</div>'
      +'</div>';
    if(have > 0){
      (function(hid){ btn.onclick = function(){ toggleComboHerb(hid); }; })(h.id);
    }
    grid.appendChild(btn);
  });

  // 슬롯 업데이트
  renderComboSlots();

  // 힌트 창 렌더링
  renderComboHints();

  // 조합 버튼 상태
  var tryBtn = document.getElementById('combo-try-btn');
  if(tryBtn){
    tryBtn.disabled = comboSelected.length < 2;
    tryBtn.style.opacity = comboSelected.length < 2 ? '.5' : '1';
    if(comboSelected.length >= 2){
      tryBtn.textContent = '🧪 조합 시도! ('+comboSelected.length+'가지)';
    } else {
      tryBtn.textContent = '🧪 조합 시도!';
    }
  }
}

function renderComboSlots(){
  var slots = document.getElementById('combo-slots');
  if(!slots) return;
  if(comboSelected.length === 0){
    slots.innerHTML = '<div style="font-size:.75rem;color:var(--ink2);font-style:italic;margin:auto">약초를 탭해서 추가하세요</div>';
    return;
  }
  slots.innerHTML = '';
  comboSelected.forEach(function(id){
    var h = COMBO_HERBS.find(function(x){return x.id===id;});
    if(!h) return;
    var chip = document.createElement('div');
    chip.style.cssText = 'display:flex;align-items:center;gap:4px;padding:5px 9px;'
      +'border-radius:20px;background:rgba(184,137,26,.15);border:1.5px solid var(--gold);'
      +'cursor:pointer;font-size:.72rem;color:var(--ink);white-space:nowrap;';
    chip.innerHTML = h.icon+' '+h.name+' <span style="color:var(--mush);margin-left:2px">✕</span>';
    chip.title = '클릭하면 제거';
    (function(hid){ chip.onclick = function(){ toggleComboHerb(hid); }; })(id);
    slots.appendChild(chip);
  });
  // + 슬롯 표시 (최대 3개)
  if(comboSelected.length < 3){
    var add = document.createElement('div');
    add.style.cssText = 'width:44px;height:44px;border-radius:8px;border:2px dashed var(--parch3);'
      +'display:flex;align-items:center;justify-content:center;font-size:1.2rem;color:var(--ink2);';
    add.textContent = '+';
    slots.appendChild(add);
  }
}

function renderComboHints(){
  var hintEl = document.getElementById('combo-hint-list');
  if(!hintEl) return;

  // 현재 선택된 재료와 관련된 힌트 표시
  var hints = [];

  // 선택된 재료가 있으면 그에 맞는 힌트
  if(comboSelected.length > 0){
    SECRET_RECIPES.forEach(function(r){
      var match = comboSelected.every(function(s){ return r.herbs.indexOf(s) >= 0; });
      if(match && r.herbs.length >= comboSelected.length){
        var needed = r.herbs.filter(function(h){ return comboSelected.indexOf(h)<0; });
        var neededNames = needed.map(function(id){
          var herb = COMBO_HERBS.find(function(x){return x.id===id;});
          return herb?herb.icon+herb.name:'?';
        });
        if(neededNames.length === 0){
          hints.push('<div style="padding:4px 0;border-bottom:1px solid var(--parch3);color:var(--gold2)">✨ 조합 가능!</div>');
        } else {
          hints.push('<div style="padding:4px 0;border-bottom:1px solid var(--parch3)">+'+neededNames.join(', ')+'<br><span style="color:var(--ink2);font-size:.6rem">→ ???</span></div>');
        }
      }
    });
  }

  // 선택 없으면 기본 힌트 목록
  if(hints.length === 0){
    hints = [
      '<div style="color:var(--ink2);padding:3px 0">🌼+💎 → ?</div>',
      '<div style="color:var(--ink2);padding:3px 0">⚡+🪨 → ?</div>',
      '<div style="color:var(--ink2);padding:3px 0">🍄+🌳 → ?</div>',
      '<div style="color:var(--ink2);padding:3px 0">🪷+🌑 → ?</div>',
      '<div style="color:var(--ink2);padding:3px 0">💎+🌿 → ?</div>',
      '<div style="color:var(--ink2);padding:3px 0;font-style:italic">도감 노트에<br>힌트 있음 👀</div>',
    ];
  }

  hintEl.innerHTML = hints.join('');
}

function toggleComboHerb(id){
  var idx = comboSelected.indexOf(id);
  if(idx >= 0){
    comboSelected.splice(idx,1);
  } else {
    if(comboSelected.length >= 3){
      // 진동 효과
      var btn = document.getElementById('combo-try-btn');
      if(btn){btn.style.border='2px solid var(--mush)';setTimeout(function(){btn.style.border='2px solid var(--gold)';},500);}
      showResult('최대 3개까지 선택 가능합니다!', true); return;
    }
    comboSelected.push(id);
    // 즉각적인 피드백
    spawnFloat(COMBO_HERBS.find(function(h){return h.id===id;}).icon+' 추가!');
  }
  renderComboHerbs();
}

function trySecretCombo(){
  if(comboSelected.length < 2){showResult('약초를 2개 이상 선택하세요!',true);return;}
  // 재료 보유 확인
  for(var i=0;i<comboSelected.length;i++){
    var id=comboSelected[i];
    var have=(G.herbs&&G.herbs[id])||0;
    if(id==='lubelily'||id==='rustcap'||id==='voltcreep') have=(G.herbCollected&&G.herbCollected[id])||0;
    if(have<1){showResult('재료가 부족합니다!',true);return;}
  }
  // 정렬해서 레시피 검색
  var key = comboSelected.slice().sort();
  var recipe = null;
  for(var r=0;r<SECRET_RECIPES.length;r++){
    if(JSON.stringify(SECRET_RECIPES[r].herbs)===JSON.stringify(key)){
      recipe=SECRET_RECIPES[r]; break;
    }
  }
  // 재료 소모
  comboSelected.forEach(function(id){
    if(id==='lubelily'||id==='rustcap'||id==='voltcreep'){
      if(G.herbCollected)G.herbCollected[id]=Math.max(0,(G.herbCollected[id]||0)-1);
    } else {
      if(G.herbs)G.herbs[id]=Math.max(0,(G.herbs[id]||0)-1);
    }
  });
  // 결과 처리
  if(recipe){
    // 성공: 즉시 적용 안 하고 선택지 제공
    showComboResultSuccess(recipe);
    if(typeof showComboCelebration==='function') showComboCelebration(recipe);
  } else {
    var fail=FAIL_RESULTS[Math.floor(Math.random()*FAIL_RESULTS.length)];
    showComboResultFail(fail);
  }
  comboSelected=[];
  updateUI();
  renderComboHerbs();
}

function applyComboEffect(recipe){
  var e=recipe.effect;
  if(e==='battle_def'){if(!G.comboBattleDef)G.comboBattleDef=0;G.comboBattleDef+=3;}
  else if(e==='walk_bonus'){G.upg.luckBonus=(G.upg.luckBonus||0)+15;}
  else if(e==='ignis_boost'){if(!G.ignisBoost)G.ignisBoost=1;}
  else if(e==='maxhp_up'){G.maxHp=(G.maxHp||100)+15;G.hp=Math.min(G.maxHp,G.hp+15);}
  else if(e==='gather_nohp'){if(!G.gatherNoHp)G.gatherNoHp=3;}
  else if(e==='energy_today'){G.maxEnergy=(G.maxEnergy||5)+2;G.energy=Math.min(G.maxEnergy,G.energy+2);}
  else if(e==='craft_double'){if(!G.craftDouble)G.craftDouble=1;}
  else if(e==='rep_up'){G.reputation=(G.reputation||0)+10;updateReputation();}
  else if(e==='full_restore'){G.hp=G.maxHp;G.energy=G.maxEnergy;G.reputation=(G.reputation||0)+5;}
  else if(e==='power_attack'){if(!G.powerAtk)G.powerAtk=1;G.hp=Math.max(1,G.hp-Math.ceil(G.maxHp*.2));}
  else if(e==='regen_boost'){if(!G.regenBoost)G.regenBoost=true;}
  else if(e==='walk_today'){if(!G.walkToday)G.walkToday=true;}
  else if(e==='codex_hint'){spawnFloat('🔮 도감 힌트 해금!');}
  else if(e==='ignis_slot'){if(!G.ignisExtraSlot)G.ignisExtraSlot=1;}
  else if(e==='steampunk_elixir'){if(!G.ignisExtraSlot)G.ignisExtraSlot=1;}
  updateHpBar();
}

// ── 성공 결과 표시 (선택지 제공) ──
function showComboResultSuccess(recipe){
  var el=document.getElementById('combo-result');
  if(!el)return;
  el.style.display='block';
  // 저장용 데이터 직렬화 (onclick에서 접근)
  window._pendingCombo = recipe;
  el.innerHTML='<div style="text-align:center;padding:14px;border-radius:10px;border:2px solid var(--gold);background:rgba(184,137,26,.1)">'
    +'<div style="font-size:2.5rem;margin-bottom:6px">'+recipe.icon+'</div>'
    +'<div style="font-family:Cinzel,serif;font-size:.95rem;color:var(--gold2)">'+recipe.name+'</div>'
    +(recipe.desc?'<div style="font-size:.75rem;color:var(--moss);margin-top:4px">'+recipe.desc+'</div>':'')
    +'<div style="font-size:.75rem;color:var(--ink2);font-style:italic;margin-top:8px;padding:8px;background:rgba(0,0,0,.04);border-radius:7px">Baba: '+recipe.baba+'</div>'
    +'<div style="display:flex;gap:6px;margin-top:12px">'
      +'<button onclick="useComboNow()" style="flex:1;padding:9px 6px;border-radius:9px;border:1.5px solid var(--moss);background:rgba(80,160,80,.15);color:var(--moss);font-size:.8rem;cursor:pointer">✨ 지금 사용</button>'
      +'<button onclick="sellCombo()" style="flex:1;padding:9px 6px;border-radius:9px;border:1.5px solid var(--gold);background:rgba(184,137,26,.15);color:var(--gold2);font-size:.8rem;cursor:pointer">💰 판매 '+recipe.sellVal+'₦</button>'
      +'<button onclick="storeCombo()" style="flex:1;padding:9px 6px;border-radius:9px;border:1.5px solid rgba(100,100,200,.5);background:rgba(100,100,200,.1);color:#8888dd;font-size:.8rem;cursor:pointer">🎒 보관</button>'
    +'</div>'
    +'</div>';
  spawnFloat(recipe.icon+' 비밀 조합 성공!');
  log('[비밀조합] 성공: '+recipe.name);
}

// ── 실패 결과 표시 ──
function showComboResultFail(fail){
  var el=document.getElementById('combo-result');
  if(!el)return;
  el.style.display='block';
  window._pendingFail = fail;
  if(!G.failItems) G.failItems=0;
  var failCount = G.failItems;
  el.innerHTML='<div style="text-align:center;padding:14px;border-radius:10px;border:2px solid var(--parch3);background:rgba(0,0,0,.05)">'
    +'<div style="font-size:2.5rem;margin-bottom:6px">'+fail.icon+'</div>'
    +'<div style="font-family:Cinzel,serif;font-size:.9rem;color:var(--ink)">'+fail.name+'</div>'
    +'<div style="font-size:.75rem;color:var(--ink2);font-style:italic;margin-top:8px;padding:8px;background:rgba(0,0,0,.04);border-radius:7px">Baba: '+fail.baba+'</div>'
    +'<div style="display:flex;gap:6px;margin-top:12px">'
      +'<button onclick="sellFail()" style="flex:1;padding:9px 6px;border-radius:9px;border:1.5px solid var(--gold);background:rgba(184,137,26,.12);color:var(--gold2);font-size:.8rem;cursor:pointer">💰 판매 '+fail.sellVal+'₦</button>'
      +'<button onclick="storeFail()" style="flex:1;padding:9px 6px;border-radius:9px;border:1.5px solid rgba(200,100,50,.5);background:rgba(200,100,50,.1);color:#cc7744;font-size:.8rem;cursor:pointer">🔄 재료로 보관 ('+(failCount+1)+'개)</button>'
    +'</div>'
    +(failCount>=2?'<div style="font-size:.7rem;color:#cc7744;margin-top:6px">💡 실패작 3개 → 폐기물 처리 발동 가능!</div>':'')
    +'</div>';
  spawnFloat('💩 실패...');
  log('[비밀조합] 실패: '+fail.name);
}

// ── 성공 아이템 액션 ──
function useComboNow(){
  var recipe=window._pendingCombo;
  if(!recipe)return;
  applyComboEffect(recipe);
  spawnFloat('✨ '+recipe.name+' 사용!');
  log('[비밀조합] '+recipe.name+' 즉시 사용');
  clearComboResult();
}
function sellCombo(){
  var recipe=window._pendingCombo;
  if(!recipe)return;
  addCoins('bronze', recipe.sellVal);
  spawnFloat('💰 +'+recipe.sellVal+'₦ 판매!');
  log('[비밀조합] '+recipe.name+' 판매 +'+recipe.sellVal+'₦');
  clearComboResult();
}
function storeCombo(){
  var recipe=window._pendingCombo;
  if(!recipe)return;
  if(!G.comboInv)G.comboInv=[];
  G.comboInv.push({id:recipe.id,name:recipe.name,icon:recipe.icon,desc:recipe.desc,effect:recipe.effect,sellVal:recipe.sellVal,baba:recipe.baba});
  spawnFloat('🎒 '+recipe.name+' 보관됨!');
  log('[비밀조합] '+recipe.name+' 인벤토리 보관');
  renderComboInventory();
  clearComboResult();
}

// ── 실패 아이템 액션 ──
function sellFail(){
  var fail=window._pendingFail;
  if(!fail)return;
  addCoins('bronze', fail.sellVal);
  spawnFloat('💰 +'+fail.sellVal+'₦ 판매!');
  clearComboResult();
}
function storeFail(){
  var fail=window._pendingFail;
  if(!fail)return;
  if(!G.failItems)G.failItems=0;
  G.failItems++;
  spawnFloat('🔄 실패작 보관 ('+G.failItems+'개)');
  // 3개 모이면 폐기물 처리 발동
  if(G.failItems>=3){
    G.failItems=0;
    triggerWasteProcessing();
  } else {
    renderComboInventory();
    clearComboResult();
  }
}

// ── 폐기물 처리 (실패작 3개) ──
function triggerWasteProcessing(){
  var luck=Math.random();
  var result='';
  var reward='';
  if(luck>0.7){
    // 대박 (30%)
    addCoins('bronze',50);addHerb('rare',2);
    result='🌟 대박! 폐기물에서 희귀 성분 추출!';
    reward='희귀초×2 + 50₦';
    spawnFloat('🌟 폐기물 처리 대박!');
  } else if(luck>0.35){
    // 중간 (35%)
    addCoins('bronze',20);addHerb('herb',3);addHerb('shroom',2);
    result='✨ 성공! 유용한 재료로 변환!';
    reward='약초×3 + 버섯×2 + 20₦';
    spawnFloat('✨ 폐기물 처리 성공!');
  } else {
    // 실패 (35%) - 그래도 조금은 줌
    addCoins('bronze',8);
    result='😅 변환 실패... 그냥 팔았어요.';
    reward='8₦';
    spawnFloat('😅 그래도 8₦는 건졌다.');
  }
  var el=document.getElementById('combo-result');
  if(el){
    el.style.display='block';
    el.innerHTML='<div style="text-align:center;padding:14px;border-radius:10px;border:2px solid rgba(200,100,50,.6);background:rgba(200,100,50,.08)">'
      +'<div style="font-size:2.5rem;margin-bottom:6px">⚗️</div>'
      +'<div style="font-family:Cinzel,serif;font-size:.9rem;color:#cc7744">바바의 비밀 폐기물 처리법 발동!</div>'
      +'<div style="font-size:.75rem;color:var(--ink2);margin-top:6px">'+result+'</div>'
      +'<div style="font-size:.8rem;color:var(--gold2);margin-top:8px;padding:7px;background:rgba(184,137,26,.1);border-radius:7px">획득: '+reward+'</div>'
      +'<div style="font-size:.7rem;color:var(--ink2);font-style:italic;margin-top:8px">Baba: "쓰레기에서 보물이 나올 줄이야. 나도 놀랐다."</div>'
      +'<button onclick="clearComboResult()" style="margin-top:10px;width:100%;padding:8px;border-radius:8px;border:1.5px solid var(--parch3);background:var(--parch);font-size:.8rem;cursor:pointer">확인</button>'
      +'</div>';
  }
  updateUI();
}

function clearComboResult(){
  window._pendingCombo=null;
  window._pendingFail=null;
  var el=document.getElementById('combo-result');
  if(el)el.style.display='none';
  updateUI();
}

// ── 보관함 렌더링 ──
function renderComboInventory(){
  var el=document.getElementById('combo-inventory');
  if(!el)return;
  if(!G.comboInv)G.comboInv=[];
  var failCnt=G.failItems||0;
  if(G.comboInv.length===0 && failCnt===0){
    el.style.display='none';
    return;
  }
  el.style.display='block';
  el.innerHTML='<div style="font-family:Cinzel,serif;font-size:.78rem;color:var(--gold2);margin-bottom:8px;border-bottom:1px solid var(--parch3);padding-bottom:5px">🎒 보관함</div>';
  // 실패작 카운트 표시
  if(failCnt>0){
    var fc=document.createElement('div');
    fc.style.cssText='display:flex;align-items:center;gap:10px;padding:8px 10px;border-radius:8px;border:1px solid rgba(200,100,50,.3);background:rgba(200,100,50,.07);margin-bottom:6px';
    fc.innerHTML='<span style="font-size:1.5rem">💩</span>'
      +'<div style="flex:1"><div style="font-size:.82rem;color:#cc7744">실패작 보관 중</div>'
      +'<div style="font-size:.68rem;color:var(--ink2);opacity:.7">'+failCnt+'/3개 — 3개 모으면 폐기물 처리 가능</div></div>';
    el.appendChild(fc);
  }
  // 성공 아이템 목록
  G.comboInv.forEach(function(item,idx){
    var card=document.createElement('div');
    card.style.cssText='display:flex;align-items:center;gap:10px;padding:8px 10px;border-radius:8px;border:1.5px solid rgba(184,137,26,.3);background:rgba(184,137,26,.07);margin-bottom:6px';
    card.innerHTML='<span style="font-size:1.8rem">'+item.icon+'</span>'
      +'<div style="flex:1"><div style="font-family:Cinzel,serif;font-size:.82rem;color:var(--gold2)">'+item.name+'</div>'
      +'<div style="font-size:.68rem;color:var(--ink2);opacity:.7">'+item.desc+'</div></div>'
      +'<div style="display:flex;flex-direction:column;gap:4px;flex-shrink:0">'
        +'<button onclick="useStoredCombo('+idx+')" style="padding:4px 8px;border-radius:6px;border:1px solid var(--moss);background:rgba(80,160,80,.12);color:var(--moss);font-size:.68rem;cursor:pointer">✨ 사용</button>'
        +'<button onclick="sellStoredCombo('+idx+')" style="padding:4px 8px;border-radius:6px;border:1px solid var(--gold);background:rgba(184,137,26,.1);color:var(--gold2);font-size:.68rem;cursor:pointer">💰 '+item.sellVal+'₦</button>'
      +'</div>';
    el.appendChild(card);
  });
}

function useStoredCombo(idx){
  if(!G.comboInv||!G.comboInv[idx])return;
  var item=G.comboInv[idx];
  applyComboEffect(item);
  spawnFloat('✨ '+item.name+' 사용!');
  G.comboInv.splice(idx,1);
  renderComboInventory();
  updateUI();
}
function sellStoredCombo(idx){
  if(!G.comboInv||!G.comboInv[idx])return;
  var item=G.comboInv[idx];
  addCoins('bronze',item.sellVal);
  spawnFloat('💰 +'+item.sellVal+'₦!');
  G.comboInv.splice(idx,1);
  renderComboInventory();
  updateUI();
}

function showComboResult(item, isSuccess){
  // 하위 호환성 유지
  if(isSuccess) showComboResultSuccess(item);
  else showComboResultFail(item);
}

// ══ ACHIEVEMENTS ══
function renderAchievements(){
  var list=document.getElementById('achievements-list');
  if(!list)return;
  list.innerHTML='';
  // 달성한 업적
  var earned=G.endings||[];
  if(earned.length===0){
    list.innerHTML='<div style="text-align:center;padding:30px;font-size:.85rem;color:var(--ink2);font-style:italic">아직 달성한 업적이 없어요.<br>게임을 계속 플레이해보세요!</div>';
    return;
  }
  earned.forEach(function(id){
    var E=ENDINGS.find(function(e){return e.id===id;});
    if(!E)return;
    var card=document.createElement('div');
    card.style.cssText='display:flex;align-items:center;gap:12px;padding:12px 14px;border-radius:10px;border:1.5px solid var(--gold);background:rgba(184,137,26,.08);margin-bottom:8px';
    card.innerHTML='<span style="font-size:2rem">'+E.icon+'</span>'
      +'<div style="flex:1"><div style="font-family:Cinzel,serif;font-size:.88rem;color:var(--gold2)">'+E.title+'</div>'
      +'<div style="font-size:.72rem;color:var(--ink2);margin-top:3px">'+E.desc+'</div></div>'
      +'<span style="font-size:.7rem;color:var(--gold2)">✅</span>';
    list.appendChild(card);
  });
  // 미달성 업적 (잠금 표시)
  ENDINGS.forEach(function(E){
    if(earned.includes(E.id))return;
    var card=document.createElement('div');
    card.style.cssText='display:flex;align-items:center;gap:12px;padding:12px 14px;border-radius:10px;border:1.5px solid var(--parch3);background:var(--parch2);margin-bottom:8px;opacity:.5';
    card.innerHTML='<span style="font-size:2rem;filter:grayscale(1)">🔒</span>'
      +'<div style="flex:1"><div style="font-family:Cinzel,serif;font-size:.88rem;color:var(--ink)">??? 미달성</div>'
      +'<div style="font-size:.72rem;color:var(--ink2);margin-top:3px">달성 조건을 찾아보세요</div></div>';
    list.appendChild(card);
  });
  // 뱃지 초기화
  var tb=document.getElementById('tb-achievements');
  if(tb)tb.style.display='none';
}

function updateForgeQueueDisplay(){
  var el=document.getElementById('forge-queue-display');
  var listEl=document.getElementById('forge-queue-list');
  if(!el||!listEl)return;
  if(!G.forgeQueue||G.forgeQueue.length===0){
    el.style.display='none';return;
  }
  el.style.display='block';
  var names={purified:'정제약초',crystal:'화염크리스탈',moonstone:'달빛석',dragonbone:'용골분말',voidmoss:'심연이끼',starresin:'별빛수지'};
  var icons={purified:'🌿',crystal:'🔥',moonstone:'🌙',dragonbone:'🦴',voidmoss:'🌑',starresin:'⭐'};
  listEl.innerHTML='';
  G.forgeQueue.forEach(function(item){
    var remaining=Math.max(0,(item.endDay||0)-G.day);
    var div=document.createElement('div');
    div.style.cssText='display:flex;align-items:center;justify-content:space-between;padding:3px 0;border-bottom:1px solid rgba(180,60,20,.1)';
    div.innerHTML=(icons[item.type]||'🔥')+' '+(names[item.type]||item.type)
      +'<span style="color:'+(remaining===0?'#60cc60':'#cc6030')+'">'
      +(remaining===0?'✅ 완성!':'Day '+item.endDay+' 완성 ('+remaining+'일 후)')
      +'</span>';
    listEl.appendChild(div);
  });
}

// ══ BATTLE SYSTEM v2 ══
