      +'<div style="flex:1">'
      +'<div style="font-size:.78rem;color:#f0c080">'+req.matName+'</div>'
      +'<div style="font-size:.65rem;color:'+(haveAll?'#a0d080':'#886644')+'">필요: '+needText+'</div>'
